import type { MessageFromTapeWorklet, MessageToTapeWorklet } from './types';
import { TAPE_LENGTH_IN_FRAMES, TAPE_ARROW_SPEED_MAGNITUDE } from './constants';
import TapeState, {
  ClipInfo,
  TAPE_STATE_LIFT_BUTTON,
  TAPE_STATE_DROP_BUTTON,
  TAPE_STATE_SPLIT_BUTTON,
  TAPE_STATE_LOOP_IN_BUTTON,
  TAPE_STATE_LOOP_OUT_BUTTON,
  TAPE_STATE_REC_BUTTON,
  TAPE_STATE_PLAY_BUTTON,
  TAPE_STATE_STOP_BUTTON,
  TAPE_STATE_LEFT_BUTTON,
  TAPE_STATE_RIGHT_BUTTON,
} from './TapeState';
import { clamp } from './helpers';
import { Metronome } from './metronome';

class Tape extends AudioWorkletProcessor implements AudioWorkletProcessorImpl {
  state: TapeState;
  prevState: TapeState;
  clips: Float32Array<any>;
  clipSamples: Float32Array<any>[];
  recordingClipInfo: (ClipInfo & { numWraps: number }) | null = null;
  liftedClipInfo: ClipInfo | null = null;
  normalizedSpeed = 0;
  speedIncrement = 0;
  desiredSpeed = 0;
  latencyOffsetInChunks = 20;
  readonly metronome = new Metronome();

  constructor() {
    super();
    this.port.onmessage = (msg: MessageEvent<MessageToTapeWorklet>) => this.onMessage(msg.data);
  }

  sendMessage(msg: MessageFromTapeWorklet, transferObjects: Transferable[] = []) {
    this.port.postMessage(msg, transferObjects);
  }

  onMessage(msg: MessageToTapeWorklet) {
    switch (msg.command) {
      case 'init': {
        this.state = TapeState.fromStateAndClipsArrays(
          new Float32Array(msg.state),
          new Float32Array(msg.clips)
        );
        this.prevState = TapeState.new();
        this.clips = new Float32Array(msg.clips);
        this.clipSamples = msg.clipSamples.map(buffer => new Float32Array(buffer));
        this.state.setGain(0, 1);
        this.state.setGain(1, 1);
        this.state.setGain(2, 1);
        this.state.setGain(3, 1);
        this.state.timeDiv = 1 / 4;
        this.state.metronomeStickDirection = 1;
        break;
      }
    }
  }

  process(inputs: Float32Array[][], [output]: Float32Array[][], _parameters: any) {
    if (!this.state) {
      // wait until we've been initialized
      return true;
    }

    this.handleButtonEvents();

    if (this.state.recording && !this.recordingClipInfo && Math.abs(this.desiredSpeed) === 1) {
      this.startRecording();
    }

    const numFrames = output[0].length;
    for (let frameIdx = 0; frameIdx < numFrames; frameIdx++) {
      if (this.state.speed !== 0) {
        this.mixClipsInto(output, frameIdx);
        if (this.recordingClipInfo) {
          this.recordFrame(inputs, frameIdx);
        }
      }

      const ph0 = this.state.playhead;
      this.advancePlayhead();
      const ph1 = this.state.playhead;

      if (this.state.clickOn) {
        this.triggerClickOnQuarterCrossings(ph0, ph1);
      }

      this.metronome.mixInto(output, frameIdx);
    }
    return true;
  }

  startRecording() {
    this.state.recording = true;
    this.state.speed = this.desiredSpeed = this.state.playingDirection;

    const offset = this.state.newClip();
    const track = this.state.selectedTrackIdx;
    const startFrameIdx =
      this.state.playingDirection > 0
        ? Math.floor(this.state.playhead)
        : Math.ceil(this.state.playhead);
    const samplesStartIdx = this.state.getNextFreeSampleIdx(track);
    const length = 0;
    this.recordingClipInfo = { offset, track, startFrameIdx, samplesStartIdx, length, numWraps: 0 };
    this.state.setClipTrackId(offset, track);
    this.state.setClipStartFrameIdx(offset, startFrameIdx);
    this.state.setClipSamplesStartIdx(offset, samplesStartIdx);
    this.state.setClipLength(offset, length);
  }

  recordFrame(inputs: Float32Array[][], frameIdx: number) {
    let sample = 0;
    for (const input of inputs) {
      sample += input[0]?.[frameIdx] ?? 0;
    }

    const { offset, track, samplesStartIdx, startFrameIdx } = this.recordingClipInfo;

    const ph = Math.floor(this.state.playhead);
    if (startFrameIdx <= ph && ph < startFrameIdx + this.recordingClipInfo.length) {
      const sampleIdx = samplesStartIdx + ph - startFrameIdx;
      this.clipSamples[track][sampleIdx] += sample; // note: this is an overdub! (good for recording while looping)
      return;
    }

    const sampleIdx = samplesStartIdx + this.recordingClipInfo.length++;
    this.state.setClipLength(offset, this.recordingClipInfo.length);
    this.clipSamples[track][sampleIdx] = sample;
    this.state.incrementNextFreeSampleIdx(track, 1);

    if (this.state.playingDirection < 0) {
      // recording backwards, so move the start of the clip back by one sample
      this.recordingClipInfo.startFrameIdx -= 1;
      this.state.setClipStartFrameIdx(offset, this.recordingClipInfo.startFrameIdx);
    }
  }

  stopRecording() {
    if (this.state.playingDirection < 0 && this.recordingClipInfo?.numWraps === 0) {
      this.reverseRecordingClipSamples();
    }

    this.state.recording = false;
    this.recordingClipInfo = null;
    this.state.recButtonDown = false;
    this.recButtonLatches = false;
  }

  reverseRecordingClipSamples() {
    const { track, samplesStartIdx, length } = this.recordingClipInfo;
    const buf = this.clipSamples[track];
    let lo = samplesStartIdx;
    let hi = samplesStartIdx + length - 1;
    while (lo < hi) {
      const t = buf[lo];
      buf[lo++] = buf[hi];
      buf[hi--] = t;
    }
  }

  recButtonLatches = false;

  handleButtonEvents() {
    this.handleButton(
      TAPE_STATE_REC_BUTTON,
      () => {
        this.state.recording = true;
        if (this.state.playButtonDown) {
          this.recButtonLatches = true;
        }
      },
      () => {
        if (!this.recButtonLatches) {
          this.stopRecording();
        }
        this.recButtonLatches = false;
      }
    );
    this.handleButton(TAPE_STATE_PLAY_BUTTON, () => {
      if (this.state.recButtonDown) {
        this.recButtonLatches = true;
      }
      const oldDirection = this.state.playingDirection;
      this.state.playingDirection = this.state.shiftButtonDown ? -1 : 1;
      this.desiredSpeed = this.state.playingDirection;
      if (this.recordingClipInfo && oldDirection !== this.state.playingDirection) {
        this.stopRecording();
      } else if (Math.abs(this.desiredSpeed) === 1) {
        // go right away, don't accelerate to it
        this.state.speed = this.desiredSpeed;
        this.speedIncrement = 0;
      }
    });
    this.handleButton(TAPE_STATE_STOP_BUTTON, () => {
      if (this.isStopped(true)) {
        this.movePlayhead(this.loopInPoint);
      } else if (this.state.recording) {
        this.state.speed = 0;
        this.speedIncrement = 0;
        this.stopRecording();
      }
      this.desiredSpeed = 0;
      this.state.playingDirection = 0;
    });
    this.handleButton(
      TAPE_STATE_LEFT_BUTTON,
      () => {
        if (this.state.stopButtonDown) {
          this.moveToStart();
        } else if (this.state.shiftButtonDown) {
          this.moveToPrevDiv();
        } else if (!this.state.recording) {
          this.desiredSpeed = -TAPE_ARROW_SPEED_MAGNITUDE;
        }
      },
      () => {
        if (!this.state.recording) {
          this.desiredSpeed = this.state.rightButtonDown
            ? TAPE_ARROW_SPEED_MAGNITUDE
            : this.state.playingDirection;
        }
      }
    );
    this.handleButton(
      TAPE_STATE_RIGHT_BUTTON,
      () => {
        if (this.state.stopButtonDown) {
          this.moveToEnd();
        } else if (this.state.shiftButtonDown) {
          this.moveToNextDiv();
        } else if (!this.state.recording) {
          this.desiredSpeed = TAPE_ARROW_SPEED_MAGNITUDE;
        }
      },
      () => {
        if (!this.state.recording) {
          this.desiredSpeed = this.state.leftButtonDown
            ? -TAPE_ARROW_SPEED_MAGNITUDE
            : this.state.playingDirection;
        }
      }
    );
    this.handleButton(TAPE_STATE_LIFT_BUTTON, () => {
      if (!this.state.recording) {
        this.lift();
      }
    });
    this.handleButton(TAPE_STATE_DROP_BUTTON, () => {
      if (!this.state.recording) {
        this.drop();
      }
    });
    this.handleButton(TAPE_STATE_SPLIT_BUTTON, () => {
      if (!this.state.recording) {
        this.split();
      }
    });
    this.handleButton(TAPE_STATE_LOOP_IN_BUTTON, () => {
      this.setLoopInPoint();
    });
    this.handleButton(TAPE_STATE_LOOP_OUT_BUTTON, () => {
      this.setLoopOutPoint();
    });

    if (!this.state.recording) {
      const u = 0.0001;
      const dir = this.desiredSpeed > this.state.speed ? 1 : -1;
      if (this.state.speed === 0 && this.desiredSpeed === 1) {
        this.speedIncrement = 1.5 * u * dir;
      } else if (this.desiredSpeed === 0) {
        // always take the same amount of time to come to a stop
        this.speedIncrement = Math.abs(this.state.speed) * u * dir;
      } else if (this.state.speed * this.desiredSpeed < 0) {
        // always take the same amount of time to change direction
        this.speedIncrement = (this.desiredSpeed - this.state.speed) * 0.5 * u;
      } else {
        this.speedIncrement = 0.75 * u * dir;
      }
    }

    this.prevState._state.set(this.state._state);
  }

  handleButton(stateIdx: number, onDown: () => void, onUp?: () => void) {
    if (this.state._state[stateIdx] === 1 && this.prevState._state[stateIdx] === 0) {
      onDown();
    } else if (this.state._state[stateIdx] === 0 && this.prevState._state[stateIdx] === 1) {
      onUp?.();
    }
  }

  mixClipsInto(output: Float32Array[], outputFrameIdx: number) {
    let sample = 0;
    this.state.forEachClip((trackIdx, startFrameIdx, length, samplesStartIdx, offset) => {
      // if (this.recordingClipInfo && offset === this.recordingClipInfo.offset) {
      //   return;
      // }
      sample +=
        this.getSampleAtPlayhead(trackIdx, startFrameIdx, length, samplesStartIdx) *
        this.state.getGain(trackIdx);
    });
    for (let channel = 0; channel < output.length; channel++) {
      output[channel][outputFrameIdx] += sample;
    }
  }

  getSampleAtPlayhead(
    trackIdx: number,
    clipStartFrameIdx: number,
    clipLength: number,
    clipSamplesStartIdx: number
  ) {
    const frameIdx = this.state.playhead - clipStartFrameIdx;
    if (frameIdx < -1 || frameIdx >= clipLength) {
      return 0;
    }

    const clipSamples = this.clipSamples[trackIdx];
    const clipSampleIdx = Math.floor(clipSamplesStartIdx + frameIdx);

    // without interpolation
    // return clipSamples[clipSampleIdx];

    // with interpolation
    const v1 = frameIdx < 0 ? 0 : clipSamples[clipSampleIdx];
    const v2 = frameIdx >= clipLength ? 0 : clipSamples[clipSampleIdx + 1];
    const f = this.state.playhead - Math.floor(this.state.playhead);
    return (1 - f) * v1 + f * v2;
  }

  inLoop() {
    return (
      this.state.loopOn &&
      Number.isFinite(this.state.loopInPoint) &&
      Number.isFinite(this.state.loopOutPoint) &&
      this.state.loopInPoint <= this.state.playhead &&
      this.state.playhead <= this.state.loopOutPoint
    );
  }

  get loopInPoint() {
    return clamp(this.state.loopInPoint, 0, TAPE_LENGTH_IN_FRAMES);
  }

  get loopOutPoint() {
    return clamp(this.state.loopOutPoint, this.loopInPoint, TAPE_LENGTH_IN_FRAMES);
  }

  private playheadWrapped = false;

  advancePlayhead() {
    this.playheadWrapped = false;
    const couldWrap = this.inLoop() && Math.abs(this.desiredSpeed) === 1;
    this.movePlayhead(this.state.playhead + this.state.speed);

    if (couldWrap) {
      if (this.state.playingDirection > 0 && this.state.playhead >= this.loopOutPoint) {
        this.playheadWrapped = true;
        this.state.playhead = this.loopInPoint + this.state.playhead - this.loopOutPoint;
      } else if (this.state.playingDirection < 0 && this.state.playhead < this.loopInPoint) {
        this.playheadWrapped = true;
        this.state.playhead = this.loopOutPoint - (this.loopInPoint - this.state.playhead);
      }
      if (this.playheadWrapped && this.recordingClipInfo) {
        this.handleWrapWhileRecording();
      }
    }

    if (this.state.speed === this.desiredSpeed) {
      // no adjustment needed
    } else if (
      Math.abs(this.desiredSpeed - this.state.speed) < Math.abs(this.speedIncrement) ||
      (this.desiredSpeed === 0 && Math.abs(this.state.speed) < 1e-2)
    ) {
      this.state.speed = this.desiredSpeed;
    } else {
      this.state.speed += this.speedIncrement;
    }
  }

  movePlayhead(newValue: number) {
    if (newValue < 0) {
      newValue = 0;
      this.state.speed = 0;
    } else if (newValue > TAPE_LENGTH_IN_FRAMES) {
      this.state.speed = 0;
      this.desiredSpeed = 0;
      this.state.playButtonDown = false;
      this.stopRecording();
      newValue = TAPE_LENGTH_IN_FRAMES;
    }
    this.state.playhead = newValue;
  }

  handleWrapWhileRecording() {
    if (++this.recordingClipInfo.numWraps !== 1) {
      // we only care about the first wrap
      return;
    }

    if (this.state.playingDirection < 0) {
      this.reverseRecordingClipSamples();
    }

    const { offset, track, startFrameIdx, samplesStartIdx, length } = this.recordingClipInfo;

    if (startFrameIdx < this.loopInPoint || startFrameIdx >= this.loopOutPoint) {
      // the clip already includes the entire loop, so we're OK
      return;
    }

    if (this.state.playingDirection > 0) {
      // going forwards:   |>    |====<|

      // 1. allocate more samples
      const n = startFrameIdx - this.loopInPoint;
      this.state.incrementNextFreeSampleIdx(track, n);
      this.recordingClipInfo.length += n;
      this.state.setClipLength(offset, this.recordingClipInfo.length);
      // note: the local variable `length` still has the old value, and we'll use it below

      // 2. shift clip left to the start of the loop
      this.recordingClipInfo.startFrameIdx = this.loopInPoint;
      this.state.setClipStartFrameIdx(offset, this.loopInPoint);

      // 3. move the samples we already recorded to the right
      // (that way they don't move relative to the tape)
      this.clipSamples[track].copyWithin(samplesStartIdx + n, samplesStartIdx, length);

      // 4. zero out the new samples
      this.clipSamples[track].fill(0, samplesStartIdx, samplesStartIdx + n);
    } else {
      // going backwards:   |>====|    <|

      // 0. reverse the samples we already recorded
      // (already did it above)

      // 1. allocate more samples
      const n = this.loopOutPoint - this.loopInPoint - length;
      this.state.incrementNextFreeSampleIdx(track, n);
      this.recordingClipInfo.length += n;
      this.state.setClipLength(offset, this.recordingClipInfo.length);
      // note: the local variable `length` still has the old value, and we'll use it below

      // 2. zero out the new samples
      this.clipSamples[track].fill(0, samplesStartIdx + length, samplesStartIdx + length + n);
    }
  }

  split() {
    const ph = Math.floor(this.state.playhead);
    const clipInfo = this.state.clipAt(ph);
    if (!clipInfo) {
      this.sendMessage({ event: 'log', message: 'no clip to split' });
      return;
    }

    const { offset, track, startFrameIdx, length, samplesStartIdx } = clipInfo;
    if (ph === startFrameIdx) {
      // it doesn't make sense to split at the start of a clip
      return;
    }

    // split the clip at the playhead
    const numFramesLeftOver = startFrameIdx + length - ph;
    clipInfo.length -= numFramesLeftOver;
    this.state.setClipLength(offset, clipInfo.length);

    // add the new clip
    const newOffset = this.state.newClip();
    this.state.setClipTrackId(newOffset, track);
    this.state.setClipStartFrameIdx(newOffset, ph);
    this.state.setClipLength(newOffset, numFramesLeftOver);
    this.state.setClipSamplesStartIdx(newOffset, samplesStartIdx + length - numFramesLeftOver);
  }

  lift() {
    const ph = Math.floor(this.state.playhead);

    // find the last clip on this track that overlaps with the playhead
    // (the second call allows the clip that ends at the playhead to be lifted)
    const clipInfo = this.state.clipAt(ph) ?? this.state.clipAt(ph, true);
    if (!clipInfo) {
      this.sendMessage({ event: 'log', message: 'no clip to lift' });
      return;
    }

    if (this.liftedClipInfo) {
      // discard the old lifted clip's samples, since they'll no longer be reachable
      const { track, samplesStartIdx, length } = this.liftedClipInfo;
      const end = this.state.getNextFreeSampleIdx(track);
      this.clipSamples[track].copyWithin(samplesStartIdx, samplesStartIdx + length, end);
      this.state.incrementNextFreeSampleIdx(track, -length);

      // now we have to adjust the samplesStartIdx of any clip whose samples were moved to the left
      this.state.forEachClip(
        (clipTrack, clipStartFrameIdx, clipLength, clipSamplesStartIdx, clipOffset) => {
          if (clipTrack === track && clipSamplesStartIdx >= samplesStartIdx) {
            this.state.setClipSamplesStartIdx(clipOffset, clipSamplesStartIdx - length);
          }
        }
      );
    }

    // clipInfo was captured before compaction; sync if this clip's samples were shifted above
    clipInfo.samplesStartIdx = this.state.getClipSamplesStartIdx(clipInfo.offset);

    // remove the clip from this.clips
    this.state.removeClip(clipInfo.offset);

    // make this clip the new lifted clip
    this.liftedClipInfo = clipInfo;

    if (this.isStopped(true)) {
      // move the playhead to the start of the lifted clip
      this.state.playhead = clipInfo.startFrameIdx;
    }

    this.sendMessage({ event: 'log', message: 'lifted clip' });
  }

  drop() {
    if (!this.liftedClipInfo) {
      this.sendMessage({ event: 'log', message: 'no clip to drop' });
      return;
    }

    const { track, samplesStartIdx, length } = this.liftedClipInfo;

    // copy the samples to the track we're dropping onto
    const samples = this.clipSamples[track].subarray(samplesStartIdx, samplesStartIdx + length);
    const newClipSampleStartIdx = this.state.getNextFreeSampleIdx(this.state.selectedTrackIdx);
    this.clipSamples[this.state.selectedTrackIdx].set(samples, newClipSampleStartIdx);
    this.state.incrementNextFreeSampleIdx(this.state.selectedTrackIdx, length);

    // add the new clip
    const quantizedPlayhead = Math.floor(this.state.playhead);
    const offset = this.state.newClip();
    this.state.setClipTrackId(offset, this.state.selectedTrackIdx);
    this.state.setClipStartFrameIdx(offset, quantizedPlayhead);
    this.state.setClipLength(offset, length);
    this.state.setClipSamplesStartIdx(offset, newClipSampleStartIdx);

    if (this.isStopped(true)) {
      // move the playhead to just after the new clip
      this.state.playhead = quantizedPlayhead + length;
    }
  }

  moveToPrevDiv() {
    const fpd = this.state.getFramesPerDiv();
    let frameIdx = Math.floor(this.state.playhead) - 1;
    const origDivIdx = this.divIndex(frameIdx, fpd);
    while (this.divIndex(frameIdx, fpd) === origDivIdx) {
      frameIdx--;
    }
    this.movePlayhead(frameIdx + 1);
  }

  moveToNextDiv() {
    const fpd = this.state.getFramesPerDiv();
    let frameIdx = Math.ceil(this.state.playhead) + 1;
    const origDivIdx = this.divIndex(frameIdx, fpd);
    while (this.divIndex(frameIdx, fpd) === origDivIdx) {
      frameIdx++;
    }
    this.movePlayhead(frameIdx - 1);
  }

  moveToStart() {
    this.movePlayhead(0);
  }

  moveToEnd() {
    const clipInfo = this.state.findClip(
      ci => true,
      (ci1, ci2) => ci1.startFrameIdx + ci1.length >= ci2.startFrameIdx + ci2.length
    );
    if (clipInfo) {
      this.movePlayhead(clipInfo.startFrameIdx + clipInfo.length);
    }
  }

  private divIndex(frameIdx: number, fpd: number) {
    return Math.floor(frameIdx / fpd);
  }

  isStopped(forceStopIfWantsToStop = false) {
    const yes = this.desiredSpeed === 0;
    if (yes && forceStopIfWantsToStop) {
      this.state.speed = 0;
      this.speedIncrement = 0;
    }
    return yes;
  }

  setLoopInPoint() {
    if (this.recordingClipInfo) {
      this.stopRecording();
    }
    this.state.loopInPoint = Math.floor(this.state.playhead);
    this.state.loopOutPoint = Math.max(this.state.loopOutPoint, this.state.loopInPoint);
  }

  setLoopOutPoint() {
    if (this.recordingClipInfo) {
      this.stopRecording();
    }
    this.state.loopOutPoint = Math.floor(this.state.playhead);
    this.state.loopInPoint = Math.min(this.state.loopInPoint, this.state.loopOutPoint);

    if (this.desiredSpeed === 1) {
      this.movePlayhead(this.loopInPoint);
    }
  }

  triggerClickOnQuarterCrossings(ph0: number, ph1: number) {
    if (ph0 === ph1) {
      return;
    }

    const fpq = this.state.getFramesPerDiv(0.25);
    const q0 = Math.floor(ph0 / fpq);
    const q1 = Math.floor(ph1 / fpq);
    const delta = ph1 - ph0;
    const step = this.state.speed;
    const stepOk = Math.abs(delta - step) < 0.05 + 0.02 * Math.abs(step);

    if (this.playheadWrapped) {
      this.metronome.click(q1 % 4 === 0);
    } else if (q0 === q1 || !stepOk) {
      // no op
    } else {
      this.metronome.click(q1 % 4 === 0);
      this.state.metronomeStickDirection *= -1;
    }
  }
}

registerProcessor('tape', Tape);
